use fastly::{http::{Request, Response}, Error, Body, RequestBuilder, Client};

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    // Define backend origins
    let backend_a = "https://backend-a.example.com";
    let backend_b = "https://backend-b.example.com";

    // Route requests based on path
    let response = match req.get_path() {
        "/service-a" => forward_request(backend_a, req),
        "/service-b" => forward_request(backend_b, req),
        _ => Response::new().with_status(404).with_body("Not Found"),
    };

    Ok(response)
}

fn forward_request(backend: &str, req: Request) -> Response {
    // Create a new request to the backend
    let client = Client::new();
    let mut backend_request = RequestBuilder::new()
        .method(req.get_method())
        .uri(backend)
        .body(req.get_body())
        .header("Host", backend)
        .build()
        .unwrap();

    // Add headers from the original request
    for (key, value) in req.iter_headers() {
        backend_request.headers_mut().insert(key, value);
    }

    // Send the request to the backend
    match client.send(backend_request) {
        Ok(response) => {
            // Return the response from the backend
            Response::new()
                .with_status(response.status())
                .with_body(response.body())
                .with_headers(response.headers())
        },
        Err(_) => Response::new().with_status(502).with_body("Bad Gateway"),
    }
}